import sys

def bfs(graph, start, h):
    visited = set()
    queue = [start]
    while queue:
        vertex = queue.pop(0)
        if vertex not in visited:
            visited.add(vertex)
            queue.extend(graph[vertex])
    return visited

def main():
    input_lines = sys.stdin.readlines()
    N, M, K = map(int, input_lines[0].split())
    graph = {i: set() for i in range(1, N+1)}
    for line in input_lines[1:M+1]:
        a, b = map(int, line.split())
        graph[a].add(b)
        graph[b].add(a)
    guards = [map(int, line.split()) for line in input_lines[M+1:]]
    guarded_vertices = set()
    for p, h in guards:
        guarded_vertices |= bfs(graph, p, h)
    print(len(guarded_vertices))
    print(*sorted(guarded_vertices))

