def is_monotonic(sequence):
    return all(sequence[i] <= sequence[i+1] for i in range(len(sequence)-1))

def is_in_range(sequence, lower_bound, upper_bound):
    return all(lower_bound <= num <= upper_bound for num in sequence)

def is_valid(sequence, lower_bound, upper_bound):
    return is_monotonic(sequence) and is_in_range(sequence, lower_bound, upper_bound)

