import sys
from math import gcd

def solve(a):
    n = len(a)
    dp = [[0] * n for _ in range(n)]
    for i in range(n):
        dp[i][i] = 0
    for l in range(2, n + 1):
        for i in range(n - l + 1):
            j = i + l - 1
            dp[i][j] = dp[i + 1][j] + dp[i][j - 1] - dp[i + 1][j - 1] + gcd(a[i], a[j])
    result = 0
    for i in range(n):
        result += dp[0][i]
    return result

def main():
    input = sys.stdin.read()
    n = int(input.split()[0])
    a = list(map(int, input.split()[1:]))
    for i in range(1, n + 1):
        print(solve(a[:i]))

