import sys
from math import gcd

def score(sequence):
    return sum(gcd(sequence[i], sequence[i+1]) for i in range(len(sequence)-1))

def subsequences(sequence):
    for i in range(1 << len(sequence)):
        mask = bin(i)[2:].zfill(len(sequence))
        subseq = [sequence[j] for j in range(len(sequence)) if mask[j] == '1']
        yield subseq

def main():
    input_lines = sys.stdin.readlines()
    N = int(input_lines[0])
    A = list(map(int, input_lines[1].split()))
    for m in range(1, N+1):
        subseq_scores = [score(subseq) for subseq in subsequences(A[:m])]
        print(sum(subseq_scores))

if __name__ == "__main__":
    main()

